func prepareScenarioFailedMetadata(res *result.ScenarioResult, sce *gauge.Scenario, executionInfo *gauge_messages.ExecutionInfo) {
	specPath := executionInfo.GetCurrentSpec().GetFileName()
	failedScenario := util.RelPathToProjectRoot(specPath)
	failedItem := fmt.Sprintf("%s:%v", failedScenario, sce.Span.Start)
	if res.GetFailed() {
		failedMeta.addFailedItem(specPath, failedItem)
	} else if isRetry(executionInfo) {
		failedMeta.removeFailedItem(specPath, failedItem)
	}
}

func isRetry(executionInfo *gauge_messages.ExecutionInfo) bool {
	return executionInfo.GetCurrentScenario().GetRetries().GetCurrentRetry() > 0
}

