package main

import (
        "bytes"
        "fmt"
        "os"
        "path/filepath"
        "sync"

        "github.com/getgauge/common"
        "github.com/getgauge/gauge-proto/go/gauge_messages"
        "github.com/getgauge/gauge/config"
        "github.com/getgauge/gauge/execution/event"
        "github.com/getgauge/gauge/execution/rerun"
        "github.com/getgauge/gauge/execution/result"
        "github.com/getgauge/gauge/gauge"
)

func emit(status gauge_messages.ExecutionStatus, currentRetry int32, scenario *gauge.Scenario, specAbs string) {
        info := &gauge_messages.ExecutionInfo{
                CurrentSpec: &gauge_messages.SpecInfo{FileName: specAbs},
                CurrentScenario: &gauge_messages.ScenarioInfo{Retries: &gauge_messages.ScenarioRetriesInfo{
                        MaxRetries:   2,
                        CurrentRetry: currentRetry,
                }},
        }
        event.Notify(event.NewExecutionEvent(event.ScenarioEnd, scenario, &result.ScenarioResult{ProtoScenario: &gauge_messages.ProtoScenario{ExecutionStatus: status}}, 0, info))
}

func runCase(name string, statuses []gauge_messages.ExecutionStatus, retries []int32, expectFailedItem bool) error {
        root, err := os.MkdirTemp("", "gauge-rerun-edge-")
        if err != nil {
                return err
        }
        defer os.RemoveAll(root)

        config.ProjectRoot = root
        specRel := filepath.Join("specs", name+".spec")
        specAbs := filepath.Join(root, specRel)
        failedItem := fmt.Sprintf("%s:2", specRel)
        scenario := &gauge.Scenario{Heading: &gauge.Heading{Value: name}, Span: &gauge.Span{Start: 2, End: 5}}

        event.InitRegistry()
        var wg sync.WaitGroup
        rerun.ListenFailedScenarios(&wg, []string{specRel})
        for i, status := range statuses {
                emit(status, retries[i], scenario, specAbs)
        }
        event.Notify(event.NewExecutionEvent(event.SuiteEnd, nil, &result.SuiteResult{}, 0, &gauge_messages.ExecutionInfo{}))
        wg.Wait()

        contents, err := os.ReadFile(filepath.Join(root, common.DotGauge, "failures.json"))
        if err != nil {
                return err
        }
        hasFailedItem := bytes.Contains(contents, []byte(failedItem))
        if hasFailedItem != expectFailedItem {
                return fmt.Errorf("%s: expected failed item present=%v, got %v\n%s", name, expectFailedItem, hasFailedItem, contents)
        }
        fmt.Printf("OK %s: failed item present=%v\n", name, hasFailedItem)
        return nil
}

